import React, { useEffect, useRef } from 'react';
import './Hero.css';

const stats = [
  { label: '월간 감정 대화', value: 50000, suffix: '+', type: 'int' },
  { label: '사용자 만족도', value: 98, suffix: '%', type: 'int' },
  { label: '평균 경험 점수', value: 4.9, suffix: '/5', type: 'float' },
];

const trustItems = [
  '감정 중심 UX 설계',
  '개인화 AI 캐릭터',
  '실시간 맥락 반응',
];

function Hero() {
  const statsRef = useRef(null);
  const visualRef = useRef(null);

  useEffect(() => {
    const animateValue = (el, target, type = 'int', suffix = '') => {
      const duration = 1600;
      const start = performance.now();

      const step = (now) => {
        const progress = Math.min((now - start) / duration, 1);
        const eased = 1 - Math.pow(1 - progress, 3);
        const current = target * eased;

        if (type === 'float') {
          el.textContent = `${current.toFixed(1)}${suffix}`;
        } else {
          el.textContent = `${Math.floor(current).toLocaleString()}${suffix}`;
        }

        if (progress < 1) requestAnimationFrame(step);
      };

      requestAnimationFrame(step);
    };

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (!entry.isIntersecting) return;
        const nodes = entry.target.querySelectorAll('.hero-metric-value');
        nodes.forEach((node, idx) => {
          const item = stats[idx];
          animateValue(node, item.value, item.type, item.suffix);
        });
        observer.disconnect();
      },
      { threshold: 0.35 }
    );

    if (statsRef.current) observer.observe(statsRef.current);
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    const node = visualRef.current;
    if (!node) return;

    const handleMove = (e) => {
      const rect = node.getBoundingClientRect();
      const x = ((e.clientX - rect.left) / rect.width) * 100;
      const y = ((e.clientY - rect.top) / rect.height) * 100;
      node.style.setProperty('--mx', `${x}%`);
      node.style.setProperty('--my', `${y}%`);
    };

    const reset = () => {
      node.style.setProperty('--mx', '50%');
      node.style.setProperty('--my', '50%');
    };

    node.addEventListener('mousemove', handleMove);
    node.addEventListener('mouseleave', reset);

    return () => {
      node.removeEventListener('mousemove', handleMove);
      node.removeEventListener('mouseleave', reset);
    };
  }, []);

  return (
    <section className="hero" id="home">
      <div className="hero-aurora hero-aurora-1"></div>
      <div className="hero-aurora hero-aurora-2"></div>
      <div className="hero-aurora hero-aurora-3"></div>

      <div className="container hero-grid">
        <div className="hero-copy">
          <div className="section-badge">차세대 AI 감정 케어 플랫폼</div>

          <h1 className="hero-title">
            감정을 이해하고
            <br />
            먼저 반응하는 <span className="gradient-text">AI 동반자</span>
          </h1>

          <p className="hero-description">
            메이티는 단순한 채팅 도구가 아닙니다. 사용자의 기분, 대화의 흐름, 일상의
            맥락을 함께 이해하며 더 부드럽고 개인화된 감정 케어 경험을 제공합니다.
          </p>

          <div className="hero-actions">
            <a href="/#download" className="btn btn-primary">
              무료로 시작하기
            </a>
            <a href="/#chat-demo" className="btn btn-secondary">
              제품 데모 보기
            </a>
          </div>

          <div className="hero-trust-row">
            {trustItems.map((item) => (
              <span key={item}>{item}</span>
            ))}
          </div>
        </div>

        <div className="hero-visual-wrap" ref={visualRef}>
          <div className="hero-visual-card glow-ring">
            <div className="hero-visual-top">
              <div className="hero-live-chip">
                <span className="hero-live-dot"></span>
                Matey AI Live
              </div>

              <div className="hero-visual-tabs">
                <span className="active">Emotion</span>
                <span>Insight</span>
                <span>Memory</span>
              </div>
            </div>

            <div className="hero-chat-window">
              <div className="hero-msg ai">
                안녕하세요. 오늘 하루에서 가장 오래 남은 감정은 무엇이었나요?
              </div>
              <div className="hero-msg user">
                괜찮은 척했는데 사실은 많이 지쳤어요.
              </div>
              <div className="hero-msg ai">
                그 마음을 숨기느라 더 힘들었겠어요. 지금은 괜찮은 척하지 않아도 돼요.
              </div>
            </div>

            <div className="hero-insight-card">
              <div className="hero-insight-label">AI Insight</div>
              <strong>최근 7일간 피로 · 불안 감정 상승 감지</strong>
              <p>대화 흐름과 반응 패턴을 바탕으로 회복 루틴과 대화 제안을 제공합니다.</p>
            </div>

            <div className="hero-floating-card left">
              <span className="mini-label">Personalized</span>
              <strong>감정 패턴 기반 추천</strong>
            </div>

            <div className="hero-floating-card right">
              <span className="mini-label">Context Aware</span>
              <strong>화면 맥락 이해</strong>
            </div>
          </div>

          <div className="hero-metrics" ref={statsRef}>
            {stats.map((item) => (
              <div className="hero-metric-card" key={item.label}>
                <div className="hero-metric-value">0</div>
                <div className="hero-metric-label">{item.label}</div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

export default Hero;
